let bcv_4d = 0;

// Extracción segura de API Oficial
let oficialApi = {};
try {
    let items = $('Fetch API Oficial').all();
    if (items && items.length > 0 && items[0].json) {
        oficialApi = items[0].json;
    }
} catch(e) {}

// Extracción segura de API Paralelo
let paralelo = 0;
try {
    let items = $('Fetch API Paralelo').all();
    if (items && items.length > 0 && items[0].json) {
        paralelo = items[0].json.promedio || items[0].json.price || 0;
    }
} catch(e) {}

// Extracción segura de BCV Web
let bcvHtml = "";
try {
    let items = $('Fetch Web BCV').all();
    if (items && items.length > 0 && items[0].json) {
        bcvHtml = items[0].json.data || "";
    }
} catch(e) {}

let web_rate = null;
let web_date_str = null;

try {
    if (bcvHtml) {
        let rateMatch = bcvHtml.match(/id\s*=\s*['"]dolar['"][\s\S]*?<strong[^>]*>([\d,.]+)/i);
        if (rateMatch && rateMatch[1]) {
            let numStr = rateMatch[1].trim().replace(',', '.');
            let parsed = parseFloat(numStr);
            if (!isNaN(parsed)) web_rate = parsed;
        }

        let dateMatch = bcvHtml.match(/class\s*=\s*['"]date-display-single['"][^>]*>([^<]+)/i);
        if (dateMatch && dateMatch[1]) {
            let rawDate = dateMatch[1].trim();
            let meses = {"Enero": "01", "Febrero": "02", "Marzo": "03", "Abril": "04", "Mayo": "05", "Junio": "06", "Julio": "07", "Agosto": "08", "Septiembre": "09", "Octubre": "10", "Noviembre": "11", "Diciembre": "12"};
            let match = rawDate.match(/(\d+)\s+([a-zA-Záéíóú]+)\s+(\d{4})/i);
            if (match) {
                let d = match[1].padStart(2, '0');
                let mesName = match[2].charAt(0).toUpperCase() + match[2].slice(1).toLowerCase();
                let mes = meses[mesName] || "01";
                let y = match[3];
                web_date_str = y + '-' + mes + '-' + d + 'T00:00:00-04:00';
            }
        }
    }
} catch(e) {
    // Si falla el parseo de BCV, web_rate quedara en null
}

let api_val = oficialApi.promedio || oficialApi.price || 0;
let api_date_str = oficialApi.fechaActualizacion;

let final_bcv = api_val;
let final_date_str = api_date_str;

let api_date_short = api_date_str ? api_date_str.substring(0, 10) : "";
let web_date_short = web_date_str ? web_date_str.substring(0, 10) : "";

// Si la web_rate existe y su fecha es mayor o igual a la de la API, la preferimos porque tiene más decimales
if (web_rate && (!api_val || web_date_short >= api_date_short)) {
    final_bcv = web_rate;
    final_date_str = web_date_str || api_date_str;
}

bcv_4d = final_bcv;

// Relajamos la restriccion: permitimos que corra aunque BCV no responda si Paralelo si respondio, y viceversa.
// Si ambos son cero, no podemos hacer insercion util.
if (!bcv_4d && !paralelo) {
    throw new Error("Tasas criticas nulas: ni BCV ni Paralelo devolvieron datos.");
}

// Si falta uno, podemos asumir que el otro debe al menos tratar de insertarse o actualizarse.
// Asignamos 0 si es null.
bcv_4d = bcv_4d || 0;
paralelo = paralelo || 0;

let bcv_2d = parseFloat(bcv_4d.toFixed(2));
let difcamb = 0;
if (bcv_4d > 0) {
    difcamb = parseFloat((paralelo / bcv_4d).toFixed(6));
}

let datesRaw = [];
try {
    let recent = $('Get Recent Dates').all();
    if (recent) {
        datesRaw = recent.map(i => String(i.json.fecha).split('T')[0]);
    }
} catch(e) {}
let existingDates = new Set(datesRaw);

let now = new Date();
let targetDate = new Date();
let useFallback = true;

if (final_date_str) {
    let apiDt = new Date(final_date_str);
    if (!isNaN(apiDt.getTime())) {
        let diffTime = Math.abs(apiDt - now);
        let diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        if (diffDays <= 30) {
            targetDate = apiDt;
            useFallback = false;
        }
    }
}

if (useFallback) {
    let hour = now.getHours();
    if (hour >= 17) {
        targetDate.setDate(now.getDate() + 1);
    }
}

let targetDateStr = targetDate.toISOString().split('T')[0];
let sql = '';

if (final_date_str && bcv_4d > 0 && paralelo > 0) {
    let apiDtOnly = new Date(targetDateStr + "T00:00:00Z");
    let startDate = new Date(now);
    startDate.setDate(now.getDate() - 30);
    startDate.setHours(0,0,0,0);

    let curr = new Date(startDate);
    while (curr <= apiDtOnly) {
        let currStr = curr.toISOString().split('T')[0];
        if (!existingDates.has(currStr)) {
            sql += "INSERT INTO dolartoday (fecha, _fecha, _hora, Dolartoday, dolarbcv, pendiente, DifCamb, fuente) VALUES ('" + currStr + "', dbo.sfAA_FechaClarion('" + currStr + "'), dbo.sfAA_HoraClarion(GETDATE()), " + paralelo + ", " + bcv_4d + ", 0, " + difcamb + ", 'api');\n";
        }
        curr.setDate(curr.getDate() + 1);
    }
}

sql += "DECLARE @targetDate DATE = '" + targetDateStr + "';\n";
sql += "DECLARE @lastPar FLOAT = (SELECT TOP 1 Dolartoday FROM dolartoday WHERE CAST(fecha AS DATE) <= CAST(GETDATE() AS DATE) AND fuente = 'api' ORDER BY fecha DESC);\n";
sql += "DECLARE @parChanged BIT = CASE WHEN ROUND(@lastPar, 2) != ROUND(" + paralelo + ", 2) THEN 1 ELSE 0 END;\n";

sql += "DECLARE @fuente VARCHAR(20) = (SELECT TOP 1 ISNULL(fuente, '') FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate ORDER BY id DESC);\n";
sql += "DECLARE @existingBcv FLOAT = (SELECT TOP 1 dolarbcv FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate AND dolarbcv IS NOT NULL AND dolarbcv > 0 ORDER BY id DESC);\n";
sql += "DECLARE @bcvLocked BIT = CASE WHEN @existingBcv IS NOT NULL AND @fuente = 'manual' AND ABS(@existingBcv - " + bcv_4d + ") > 0.00001 THEN 1 ELSE 0 END;\n";
sql += "DECLARE @bcvChanged BIT = CASE WHEN ABS(ISNULL((SELECT TOP 1 Factor FROM SACONF), 0) - " + bcv_4d + ") > 0.00001 OR ABS(ISNULL(@existingBcv, 0) - " + bcv_4d + ") > 0.00001 THEN 1 ELSE 0 END;\n";

// Si traemos bcv, actualizamos SACONF, etc
if (bcv_4d > 0) {
    sql += "IF (@bcvLocked = 0 AND @bcvChanged = 1)\n";
    sql += "BEGIN\n";
    sql += "    DECLARE @lastIdBefore INT = (SELECT ISNULL(MAX(id), 0) FROM dolartoday WHERE CAST(fecha AS DATE) = CAST(GETDATE() AS DATE));\n";
    sql += "    UPDATE SACONF SET Factor = " + bcv_4d + ", FactorM = " + bcv_4d + ";\n";
    sql += "    UPDATE SATARJ SET Monto = " + bcv_4d + " WHERE TipoIns = 0;\n";
    sql += "    IF (@targetDate != CAST(GETDATE() AS DATE)) DELETE FROM dolartoday WHERE CAST(fecha AS DATE) = CAST(GETDATE() AS DATE) AND id > @lastIdBefore;\n";
    sql += "    IF EXISTS (SELECT 1 FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate)\n";
    sql += "        UPDATE dolartoday SET " + (paralelo > 0 ? "Dolartoday = " + paralelo + "," : "") + " pendiente = 0, DifCamb = " + difcamb + ", _hora = dbo.sfAA_HoraClarion(GETDATE()), fuente = 'api' WHERE id = (SELECT TOP 1 id FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate ORDER BY id DESC);\n";
    sql += "    ELSE\n";
    sql += "        INSERT INTO dolartoday (fecha, _fecha, _hora, Dolartoday, dolarbcv, pendiente, DifCamb, fuente) VALUES (@targetDate, dbo.sfAA_FechaClarion(@targetDate), dbo.sfAA_HoraClarion(GETDATE()), " + (paralelo > 0 ? paralelo : "NULL") + ", " + bcv_4d + ", 0, " + difcamb + ", 'api');\n";
    sql += "END\n";
}

if (paralelo > 0) {
    sql += "ELSE IF (@parChanged = 1)\n";
    sql += "BEGIN\n";
    sql += "    DECLARE @lastIdBeforePar INT = (SELECT ISNULL(MAX(id), 0) FROM dolartoday WHERE CAST(fecha AS DATE) = CAST(GETDATE() AS DATE));\n";
    sql += "    IF EXISTS (SELECT 1 FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate)\n";
    sql += "        UPDATE dolartoday SET Dolartoday = " + paralelo + ", pendiente = 0, DifCamb = ROUND(" + paralelo + " / NULLIF(ISNULL(@existingBcv, dolarbcv), 0), 6), _hora = dbo.sfAA_HoraClarion(GETDATE()) WHERE id = (SELECT TOP 1 id FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate ORDER BY id DESC);\n";
    sql += "    ELSE\n";
    sql += "        INSERT INTO dolartoday (fecha, _fecha, _hora, Dolartoday, dolarbcv, pendiente, DifCamb, fuente) VALUES (@targetDate, dbo.sfAA_FechaClarion(@targetDate), dbo.sfAA_HoraClarion(GETDATE()), " + paralelo + ", " + (bcv_4d > 0 ? bcv_4d : "NULL") + ", 0, " + (bcv_4d > 0 ? difcamb : "NULL") + ", 'api');\n";
    sql += "    IF (@targetDate != CAST(GETDATE() AS DATE)) DELETE FROM dolartoday WHERE CAST(fecha AS DATE) = CAST(GETDATE() AS DATE) AND id > @lastIdBeforePar;\n";
    sql += "END\n";
}

sql += "ELSE\n";
sql += "BEGIN\n";
sql += "    IF EXISTS (SELECT 1 FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate)\n";
sql += "        UPDATE dolartoday SET _hora = dbo.sfAA_HoraClarion(GETDATE()) WHERE id = (SELECT TOP 1 id FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate ORDER BY id DESC);\n";
sql += "END\n";

if (paralelo > 0) {
    sql += "UPDATE dolartoday SET Dolartoday = " + paralelo + ", pendiente = 0, DifCamb = ROUND(" + paralelo + " / NULLIF(dolarbcv, 0), 6) WHERE (pendiente = 1 OR Dolartoday IS NULL OR DifCamb IS NULL);\n";
}
sql += "UPDATE dolartoday SET fuente = 'manual' WHERE fuente IS NULL AND ROUND(dolarbcv, 2) = dolarbcv;\n";
sql += "UPDATE dolartoday SET fuente = 'bot_trigger' WHERE fuente IS NULL;\n";
sql += "DELETE FROM dolartoday WHERE fuente IN ('manual', 'bot_trigger') AND CAST(fecha AS DATE) IN (SELECT CAST(fecha AS DATE) FROM dolartoday WHERE fuente = 'api');\n";

sql += "WITH CTE AS (SELECT id, ROW_NUMBER() OVER(PARTITION BY CAST(fecha AS DATE) ORDER BY id DESC) as rn FROM dolartoday)\n";
sql += "DELETE FROM dolartoday WHERE id IN (SELECT id FROM CTE WHERE rn > 1);\n";

return { json: { sql: sql } };

let apiOficial = {};
let apiParalelo = {};
let webBcv = {};

let apiOficialExecuted = false;
let apiParaleloExecuted = false;
let webBcvExecuted = false;

try {
    let items = $('Fetch API Oficial').all();
    if (items && items.length > 0) {
        apiOficialExecuted = true;
        apiOficial = items[0].json;
    }
} catch(e) {}

try {
    let items = $('Fetch API Paralelo').all();
    if (items && items.length > 0) {
        apiParaleloExecuted = true;
        apiParalelo = items[0].json;
    }
} catch(e) {}

try {
    let items = $('Fetch Web BCV').all();
    if (items && items.length > 0) {
        webBcvExecuted = true;
        webBcv = items[0].json;
    }
} catch(e) {}

let errorMessages = [];

if (apiParalelo.error) {
    errorMessages.push("Tasa Paralelo [Fallo API - Timeout o Error]");
} else if (!apiParalelo.promedio && !apiParalelo.price) {
    errorMessages.push("Tasa Paralelo [Fallo API - Sin datos válidos]");
}

let oficialFallo = false;
if (apiOficial.error) {
    oficialFallo = true;
    errorMessages.push("Tasa BCV Oficial [Fallo API - Timeout o Error]");
} else if (!apiOficial.promedio && !apiOficial.price) {
    oficialFallo = true;
    errorMessages.push("Tasa BCV Oficial [Fallo API - Sin datos válidos]");
}

if (oficialFallo) {
    if (webBcvExecuted) {
        if (webBcv.error) {
            errorMessages.push("Scraper BCV Fallback [Fallo - Error al raspar]");
        } else if (!webBcv.data) {
            errorMessages.push("Scraper BCV Fallback [Fallo - Sin HTML]");
        } else {
            let rateMatch = webBcv.data.match(/id\s*=\s*['"]dolar['"][\s\S]*?<strong[^>]*>([\d,.]+)/i);
            if (!rateMatch || !rateMatch[1]) {
                errorMessages.push("Scraper BCV Fallback [Fallo - No se encontró la tasa en el HTML]");
            }
        }
    } else {
        errorMessages.push("Scraper BCV Fallback [No se ejecutó inesperadamente]");
    }
}

if (errorMessages.length > 0) {
    let msg = "Reporte de Extracción Parcial:\n- " + errorMessages.join("\n- ");
    throw new Error(msg);
}

return [{ json: { success: true, message: "Todas las fuentes solicitadas respondieron correctamente" } }];
